function sha256Utf8Hex(str) {
  var bin = '';
  var u8 = new TextEncoder().encode(String(str || ''));
  for (var bi = 0; bi < u8.length; bi++) bin += String.fromCharCode(u8[bi]);
  return sha256RawBytesString(bin);
}
function sha256RawBytesString(ascii) {
  function rightRotate(value, amount) {
    return (value >>> amount) | (value << (32 - amount));
  }
  var mathPow = Math.pow;
  var maxWord = mathPow(2, 32);
  var lengthProperty = 'length';
  var i, j;
  var result = '';
  var words = [];
  var asciiBitLength = ascii[lengthProperty] * 8;
  var hash = [];
  var k = [];
  var primeCounter = 0;
  var isComposite = {};
  for (var candidate = 2; primeCounter < 64; candidate++) {
    if (!isComposite[candidate]) {
      for (i = 0; i < 313; i += candidate) isComposite[i] = candidate;
      hash[primeCounter] = (mathPow(candidate, 0.5) * maxWord) | 0;
      k[primeCounter++] = (mathPow(candidate, 1 / 3) * maxWord) | 0;
    }
  }
  ascii += '\x80';
  while (ascii[lengthProperty] % 64 - 56) ascii += '\x00';
  for (i = 0; i < ascii[lengthProperty]; i++) {
    j = ascii.charCodeAt(i);
    if (j >> 8) throw new Error('sha256: byte inválido');
    words[i >> 2] |= j << ((3 - i) % 4) * 8;
  }
  words[words[lengthProperty]] = (asciiBitLength / maxWord) | 0;
  words[words[lengthProperty]] = asciiBitLength;
  for (j = 0; j < words[lengthProperty];) {
    var w = words.slice(j, (j += 16));
    var oldHash = hash;
    hash = hash.slice(0, 8);
    for (i = 0; i < 64; i++) {
      var w15 = w[i - 15],
        w2 = w[i - 2];
      var a = hash[0],
        e = hash[4];
      var temp1 =
        hash[7] +
        (rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25)) +
        ((e & hash[5]) ^ (~e & hash[6])) +
        k[i] +
        (w[i] =
          i < 16
            ? w[i]
            : (w[i - 16] +
                (rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15 >>> 3)) +
                w[i - 7] +
                (rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2 >>> 10))) |
              0);
      var temp2 =
        (rightRotate(a, 2) ^ rightRotate(a, 13) ^ rightRotate(a, 22)) +
        ((a & hash[1]) ^ (a & hash[2]) ^ (hash[1] & hash[2]));
      hash = [(temp1 + temp2) | 0].concat(hash);
      hash[4] = (hash[4] + temp1) | 0;
    }
    for (i = 0; i < 8; i++) hash[i] = (hash[i] + oldHash[i]) | 0;
  }
  for (i = 0; i < 8; i++) {
    for (j = 3; j + 1; j--) {
      var b = (hash[i] >> (j * 8)) & 255;
      result += (b < 16 ? '0' : '') + b.toString(16);
    }
  }
  return result;
}

function normalizeArticleUrl(raw) {
  const s = String(raw || '').trim();
  if (!s) return '';
  try {
    const x = new URL(s);
    if (x.protocol === 'http:') x.protocol = 'https:';
    x.hash = '';
    let host = x.hostname.toLowerCase();
    if (host.startsWith('www.')) host = host.slice(4);
    x.hostname = host;
    const dropParams = [
      'utm_source', 'utm_medium', 'utm_campaign', 'utm_content', 'utm_term', 'utm_id',
      'ref', 'fbclid', 'gclid', 'mc_cid', 'mc_eid', 'igshid', '_branch_match_id', 'trk', 'trkparam'
    ];
    for (const k of dropParams) x.searchParams.delete(k);
    const qs = x.searchParams.toString();
    x.search = qs ? `?${qs}` : '';
    let p = x.pathname.replace(/\/+$/, '');
    x.pathname = p || '/';
    return x.href;
  } catch {
    return s;
  }
}

function pathFingerprint(normalizedHref) {
  const h = String(normalizedHref || '').trim();
  if (!h) return '';
  try {
    const x = new URL(h);
    let host = x.hostname.toLowerCase();
    if (host.startsWith('www.')) host = host.slice(4);
    let path = x.pathname.replace(/\/+$/, '') || '/';
    return sha256Utf8Hex(`${x.protocol}//${host}${path}`);
  } catch {
    return '';
  }
}

function normalizeForDedupeText(t) {
  return String(t || '')
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function contentDedupeHash(title, snippet) {
  const a = normalizeForDedupeText(title).slice(0, 220);
  const b = normalizeForDedupeText(snippet).slice(0, 450);
  return sha256Utf8Hex(`${a}||${b}`);
}

function hashItemId(url) {
  return sha256Utf8Hex(url);
}

function wfGlobal() {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (typeof getWorkflowStaticData === 'function') return getWorkflowStaticData('global');
  throw new Error('Static data indisponível: atualize o n8n ou use workflow ativo.');
}

const allItems = $input.all();
const items = allItems.map(item => item.json);

const staticData = wfGlobal();
staticData.postedIds = staticData.postedIds || [];
if (!staticData._legacyPostedUrlsMigrated && staticData.postedUrls && staticData.postedUrls.length) {
  for (const u of staticData.postedUrls) {
    const nid = hashItemId(normalizeArticleUrl(u));
    if (!staticData.postedIds.includes(nid)) staticData.postedIds.unshift(nid);
  }
  staticData._legacyPostedUrlsMigrated = true;
}
const postedIdSet = new Set(staticData.postedIds);

staticData.postedPathHashes = staticData.postedPathHashes || [];
staticData.postedContentHashes = staticData.postedContentHashes || [];
const postedPathSet = new Set(staticData.postedPathHashes);
const postedContentSet = new Set(staticData.postedContentHashes);

// Pelo menos UMA âncora forte (Cloud / DevOps / SRE / infra / rede / ciber) — evita "monitoring" genérico em posts de IA
const primaryAnchors = [
  'devops', 'sre', 'site reliability', 'platform engineering',
  'kubernetes', 'k8s', 'terraform', 'ansible', 'helm', 'gitops',
  'ci/cd', 'cicd', 'pipeline', 'jenkins', 'argocd', 'gitlab',
  'container', 'docker', 'pod ', 'namespace', 'kubectl',
  'serverless', 'lambda', 'fargate', 'cloudformation', 'aws cdk', 'cdk ',
  'microservice', 'service mesh', 'istio', 'linkerd', 'envoy',
  'vpc', 'subnet', 'load balancer', 'cloudfront', 'api gateway',
  'eks', 'gke', ' aks', 'openshift',
  'prometheus', 'grafana', 'opentelemetry', 'observability',
  'infrastructure as code', 'iac',
  'zero trust', 'iam', 'oauth', 'saml', 'cve', 'vulnerability',
  'devsecops', 'sbom', 'supply chain',
  'finops', 'cost optimization', 'reserved instance',
  'disaster recovery', 'multi-region', 'high availability',
  'postmortem', 'on-call', 'pagerduty',
  'network policy', 'firewall', 'ddos', 'waf', 'intrusion',
  'encryption', 'tls', 'mtls', 'rbac',
  'hybrid cloud', 'multi-cloud',
  'segurança da informação', 'security operations', 'soc ',
  'routing protocol', 'bgp', 'sdn', 'network automation'
];

const excludeKeywords = [
  'artificial intelligence', 'machine learning', 'deep learning',
  'large language model', 'llm', 'generative ai', 'gen ai',
  'chatgpt', 'copilot', 'neural network', 'data science', 'nlp', 'gpt-',
  'computer vision', 'foundation model', 'fine-tuning', 'fine tuning',
  'prompt engineering', 'hallucination', 'sagemaker', 'sage maker',
  'workplace safety', 'occupational safety', 'osha', 'industrial safety',
  'computer vision', 'video analytics', 'object detection', 'yolo',
  'vagas', 'emprego', 'promoção', 'marketing', 'webinar', 'survey',
  'report 2025', 'report 2026'
];

const scoreKeywords = [
  'devops', 'sre', 'site reliability', 'platform engineering',
  'ci/cd', 'cicd', 'pipeline', 'gitops', 'terraform', 'ansible',
  'helm', 'observability', 'monitoring', 'alerting', 'incident',
  'postmortem', 'on-call', 'resilience', 'reliability',
  'cloud', 'kubernetes', 'k8s', 'container', 'serverless', 'microservice',
  'service mesh', 'istio', 'multi-cloud', 'hybrid cloud',
  'security', 'segurança', 'zero trust', 'iam', 'identity', 'vulnerability',
  'cve', 'patch', 'compliance', 'devsecops', 'supply chain',
  'rbac', 'encryption', 'architecture', 'best practice',
  'design pattern', 'scalability', 'high availability',
  'disaster recovery', 'cost optimization', 'finops'
];

const scored = items
  .filter(item => {
    const text = ((item.title || '') + ' ' + (item.contentSnippet || item.summary || '')).toLowerCase();
    if (excludeKeywords.some(kw => text.includes(kw))) return false;
    if (!primaryAnchors.some(kw => text.includes(kw))) return false;
    return true;
  })
  .map(item => {
    const text = ((item.title || '') + ' ' + (item.contentSnippet || item.summary || '')).toLowerCase();
    const score = scoreKeywords.filter(kw => text.includes(kw)).length;
    const pubDate = new Date(item.pubDate || item.isoDate || 0);
    const ageHours = (Date.now() - pubDate.getTime()) / 3600000;
    const recencyBonus = ageHours < 24 ? 5 : ageHours < 48 ? 2 : 0;
    return { ...item, _score: score + recencyBonus };
  })
  .sort((a, b) => b._score - a._score);

if (scored.length === 0) {
  return [];
}

const fresh = [];
for (const item of scored) {
  const raw = String(item.link || item.url || '').trim();
  const uNorm = normalizeArticleUrl(raw);
  if (!uNorm) continue;
  const idRaw = hashItemId(raw);
  const idNorm = hashItemId(uNorm);
  const pk = pathFingerprint(uNorm);
  const ch = contentDedupeHash(item.title || '', item.contentSnippet || item.summary || '');
  if (postedIdSet.has(idRaw) || postedIdSet.has(idNorm)) continue;
  if (pk && postedPathSet.has(pk)) continue;
  if (ch && postedContentSet.has(ch)) continue;
  fresh.push(item);
}

if (fresh.length === 0) {
  return [];
}

fresh.sort((a, b) => {
  const ta = new Date(a.pubDate || a.isoDate || 0).getTime();
  const tb = new Date(b.pubDate || b.isoDate || 0).getTime();
  if (tb !== ta) return tb - ta;
  return (b._score || 0) - (a._score || 0);
});

const seenPath = new Set();
const seenContent = new Set();
const freshUnique = [];
for (const item of fresh) {
  const raw = String(item.link || item.url || '').trim();
  const uNorm = normalizeArticleUrl(raw);
  const pk = pathFingerprint(uNorm);
  const ch = contentDedupeHash(item.title || '', item.contentSnippet || item.summary || '');
  if ((pk && seenPath.has(pk)) || (ch && seenContent.has(ch))) continue;
  if (pk) seenPath.add(pk);
  if (ch) seenContent.add(ch);
  freshUnique.push(item);
}

if (freshUnique.length === 0) {
  return [];
}

const top = freshUnique[0];
const rawUrl = String(top.link || top.url || '').trim();
const url = normalizeArticleUrl(rawUrl);
const itemId = hashItemId(rawUrl);
const itemIdNorm = hashItemId(url);
const pathDedupeKey = pathFingerprint(url);
const contentDedupeKey = contentDedupeHash(top.title || '', top.contentSnippet || top.summary || '');
return [{
  json: {
    title: top.title || '',
    url,
    itemId,
    itemIdNorm,
    pathDedupeKey,
    contentDedupeKey,
    summary: (top.contentSnippet || top.summary || '').substring(0, 600),
    pubDate: top.pubDate || top.isoDate || new Date().toISOString(),
    score: top._score
  }
}];

function stripMarkdownForLinkedIn(s) {
  let t = String(s || '');
  for (let i = 0; i < 4; i++) {
    t = t.replace(/\*\*([\s\S]*?)\*\*/g, '$1');
    t = t.replace(/__([\s\S]*?)__/g, '$1');
  }
  t = t.replace(/`([^`]+)`/g, '$1');
  t = t.replace(/\*\*/g, '');
  t = t.replace(/\*([^*\n]+)\*/g, '$1');
  t = t.replace(/_([^_\n]+)_/g, '$1');
  return t.replace(/\n{3,}/g, '\n\n').trim();
}

const geminiResponse = $input.first().json;
const articleData = $('Filtrar e Selecionar Artigo').first().json;
const candidate = geminiResponse?.candidates?.[0];
const parts = candidate?.content?.parts || [];
const visible = parts.filter((p) => p && p.thought !== true && typeof p.text === 'string');
const raw = stripMarkdownForLinkedIn(visible.map((p) => p.text).filter(Boolean).join(''));

if (!raw) {
  throw new Error('Gemini não retornou texto para o post.');
}

let editorialTitle = '';
let postText = raw;

const tituloM = raw.match(/^T[IÍ]TULO:\s*(.+)$/im) || raw.match(/^TITULO:\s*(.+)$/im);
const corpoM = raw.match(/\bCORPO:\s*([\s\S]+)/is);

if (tituloM && corpoM) {
  editorialTitle = tituloM[1].replace(/\s+/g, ' ').trim();
  postText = corpoM[1].trim();
} else {
  const lines = raw.split(/\r?\n/).map((l) => l.trim()).filter(Boolean);
  if (lines.length >= 2) {
    let first = lines[0].replace(/^(T[IÍ]TULO|TITULO):\s*/i, '').trim();
    editorialTitle = first;
    postText = lines.slice(1).join('\n\n').replace(/^CORPO:\s*/i, '').trim();
  }
}

if (!postText) {
  throw new Error('Não foi possível extrair o CORPO do post.');
}

if (editorialTitle.length > 120) {
  editorialTitle = editorialTitle.slice(0, 117).trim() + '…';
}

return [{
  json: {
    editorialTitle,
    postText,
    articleTitle: articleData.title,
    articleUrl: articleData.url,
    articleSummary: articleData.summary
  }
}];

