const postData = $('Extrair Texto do Post').first().json;
const geminiHashtagsResp = $input.first().json;
const tagCand = geminiHashtagsResp?.candidates?.[0];
const tagParts = tagCand?.content?.parts || [];
let hashtags = tagParts.map((p) => p.text).filter(Boolean).join('').replace(/\s+/g, ' ').trim();
if (!hashtags || tagCand?.finishReason === 'MAX_TOKENS') {
  hashtags = '#Cloud #DevOps #SRE #Infraestrutura #Tech';
}

const url = String(postData.articleUrl || '').trim();
const sep = '\n\n';
const LINKEDIN_TEXT_MAX = 2950;

const headline = String(postData.editorialTitle || '').trim();
let body = String(postData.postText || '').trim();
let mainBlock = headline ? `${headline}${sep}${body}` : body;

let full = url ? `${mainBlock}${sep}${hashtags}${sep}${url}` : `${mainBlock}${sep}${hashtags}`;
if (full.length > LINKEDIN_TEXT_MAX) {
  const tail = url ? `${sep}${hashtags}${sep}${url}` : `${sep}${hashtags}`;
  const headPrefix = headline ? `${headline}${sep}` : '';
  const maxBody = LINKEDIN_TEXT_MAX - tail.length - headPrefix.length;
  if (maxBody > 200) {
    body = body.slice(0, maxBody - 1).replace(/\s+\S*$/, '').trim() + '…';
    mainBlock = headline ? `${headline}${sep}${body}` : body;
    full = url ? `${mainBlock}${sep}${hashtags}${sep}${url}` : `${mainBlock}${sep}${hashtags}`;
  }
}

const linkedInMediaTitle = (headline || String(postData.articleTitle || '')).replace(/\s+/g, ' ').trim().slice(0, 200);

function hashStr(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h) ^ s.charCodeAt(i);
  return Math.abs(h >>> 0);
}

const seed = hashStr(String(postData.articleUrl || '') + '|' + String(postData.articleTitle || ''));
const visualStyles = [
  'Photorealistic editorial photograph: natural daylight, deep depth of field so foreground and background stay sharp, fine texture detail, no haze.',
  'Cinematic wide shot with gentle lighting but entire frame in focus (f/8–f/11 look), crisp edges on props, no tilt-shift or miniature blur.',
  'Detail-rich scene echoing the topic: sharp focus throughout, clear materials (metal, glass, concrete), avoid glow smear or dreamy blur.',
  'Authentic workspace still (no faces, logos, or screens with text): mixed light but high clarity, all main objects readable and sharp.',
  'Infrastructure or architecture scene: geometric precision, neutral grade, sharp from near to far — no heavy bokeh or soft vignette haze.',
  'Photoreal 3D product-style render: clean studio lighting, crisp shadows, anti-aliased edges, no depth-of-field blur on the hero subject.',
  'Environmental shot with real sky or interior: atmospheric perspective only if subtle; main subject and midground must stay tack sharp.',
  'Editorial still life: one clear focal arrangement, textured surfaces rendered with sharp micro-detail, no fuzzy glow around objects.',
];
const stylePick = visualStyles[seed % visualStyles.length];

const sum = (postData.articleSummary || '').replace(/\s+/g, ' ').trim().slice(0, 300);
const title = String(postData.articleTitle || '').trim().slice(0, 220);
const hook = [headline, body].filter(Boolean).join(' — ').replace(/\s+/g, ' ').trim().slice(0, 220);

const imagePrompt = `Professional editorial illustration — subject matter only. Visualize the technical and business themes of the piece below; do not depict any social network, publishing tool, or "post" layout. Source article themes (English): ${title}. Context: ${sum}. Editorial angle to inspire visuals only — never render as words, captions, or labels: ${hook}. Visual treatment: ${stylePick} Image quality: tack sharp, deep focus, no shallow depth-of-field gimmicks, no tilt-shift, no heavy bokeh haze. Forbidden: all text, letters, numbers, glyphs, fake typography, subtitles, watermarks, brand marks, app UI, phone or laptop screens showing feeds, notification bubbles, profile avatars in a social layout, or "card" frames like a social timeline. Forbidden: LinkedIn logo or "in" icon, Facebook, Instagram, X/Twitter, or any recognizable social-platform branding or metaphor for "networking" or "likes". Use only concrete or abstract imagery tied to the editorial topic (infrastructure, security, operations, engineering, architecture, data centers, tools as objects without readable labels). Avoid generic blue tech gradients and decorative cloud clipart unless the topic is genuinely about cloud platforms.`;

return [{
  json: {
    editorialTitle: headline,
    postText: body,
    hashtags,
    fullPostText: full,
    linkedInMediaTitle,
    imagePrompt,
    articleTitle: postData.articleTitle,
    articleUrl: postData.articleUrl,
    articleSummary: postData.articleSummary
  }
}];

