const linkedinRegisterResp = $input.first().json;
const postData = $('Extrair URL da Imagem').first().json;
const downloadItem = $('Download Imagem DALL-E').first();

const uploadUrl = linkedinRegisterResp?.value?.uploadMechanism?.['com.linkedin.digitalmedia.uploading.MediaUploadHttpRequest']?.uploadUrl;
const assetUrn = linkedinRegisterResp?.value?.asset;

if (!uploadUrl || !assetUrn) {
  throw new Error(`LinkedIn Register Upload falhou. Resposta: ${JSON.stringify(linkedinRegisterResp)}`);
}

if (!downloadItem.binary?.data) {
  throw new Error('Binário da imagem ausente: confirme Download Imagem DALL-E com responseFormat file (binary data).');
}

return [{
  json: {
    ...postData,
    uploadUrl,
    assetUrn
  },
  binary: downloadItem.binary
}];

