function wfGlobal() {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (typeof getWorkflowStaticData === 'function') return getWorkflowStaticData('global');
  throw new Error('Static data indisponível');
}
const staticData = wfGlobal();
staticData.postedIds = staticData.postedIds || [];
staticData.postedPathHashes = staticData.postedPathHashes || [];
staticData.postedContentHashes = staticData.postedContentHashes || [];
const row = $('Filtrar e Selecionar Artigo').first().json;
const ids = [row.itemId, row.itemIdNorm].filter(Boolean);
for (const id of ids) {
  if (id && !staticData.postedIds.includes(id)) staticData.postedIds.unshift(id);
}
staticData.postedIds = staticData.postedIds.slice(0, 2000);
const pathK = row.pathDedupeKey;
const contK = row.contentDedupeKey;
if (pathK && !staticData.postedPathHashes.includes(pathK)) staticData.postedPathHashes.unshift(pathK);
if (contK && !staticData.postedContentHashes.includes(contK)) staticData.postedContentHashes.unshift(contK);
staticData.postedPathHashes = staticData.postedPathHashes.slice(0, 2000);
staticData.postedContentHashes = staticData.postedContentHashes.slice(0, 2000);
return $input.all();
